// SAT Math Question Bank — 500 Questions
// Distribution mirrors Digital SAT: Algebra 35%, Advanced Math 35%, Problem Solving 15%, Geometry 15%

export const CATS = ["Algebra", "Advanced Math", "Problem Solving", "Geometry"];
export const DIFFS = ["Easy", "Medium", "Hard"];

export const SAT_CURVE = {44:800,43:790,42:780,41:770,40:760,39:750,38:740,37:730,36:720,35:710,34:700,33:690,32:680,31:670,30:660,29:650,28:640,27:630,26:620,25:610,24:590,23:580,22:560,21:550,20:540,19:530,18:510,17:500,16:490,15:480,14:460,13:450,12:440,11:430,10:410,9:400,8:390,7:380,6:360,5:350,4:330,3:310,2:280,1:240,0:200};

export function rawToScaled(correct, total) {
  const projected = Math.round((correct / total) * 44);
  return SAT_CURVE[projected] ?? 200;
}

